package com.mccompanion.terminal.install;
import com.mccompanion.terminal.launcher.*;import java.nio.file.*;import java.util.*;import java.util.zip.*;import org.junit.jupiter.api.*;import org.junit.jupiter.api.io.TempDir;import static org.junit.jupiter.api.Assertions.*;
class ArtifactResolverTest{@TempDir Path temp;MinecraftInstance instance(){return new MinecraftInstance("i","l","x",temp,temp,temp,temp,temp,temp,"1.21.1",LoaderType.FABRIC,"1",21,Optional.empty(),InstanceIsolation.EXPLICIT,DetectionConfidence.HIGH);}void jar(Path p,String mc)throws Exception{Files.createDirectories(p.getParent());try(var z=new ZipOutputStream(Files.newOutputStream(p))){z.putNextEntry(new ZipEntry("fabric.mod.json"));z.write(("{\"id\":\"minecraft_ai_companion\",\"version\":\"0.2\",\"depends\":{\"minecraft\":\"="+mc+"\"}}").getBytes());z.closeEntry();}}
 @Test void exactMetadataSelected()throws Exception{Path d=temp.resolve("fabric-1.21.1");jar(d.resolve("good.jar"),"1.21.1");jar(d.resolve("wrong.jar"),"1.20.1");assertEquals("good.jar",new ArtifactResolver().resolve(instance(),temp).orElseThrow().getFileName().toString());}
 @Test void multipleExactCandidatesBlocked()throws Exception{Path d=temp.resolve("fabric-1.21.1");jar(d.resolve("a.jar"),"1.21.1");jar(d.resolve("b.jar"),"1.21.1");assertThrows(java.io.IOException.class,()->new ArtifactResolver().resolve(instance(),temp));}}
